export const PrimTypeSupport: DdsTopicType<Prim> = {
    typeName: "feat::Prim",
    isKeyed: false,
    extensibility: "appendable",
    encodeInto(w: Xcdr2Writer, s: Prim): void {
        const _tok = w.beginAppendable();
        w.writeInt8(s.i8);
        w.writeUint8(s.u8);
        w.writeInt16(s.i16);
        w.writeUint16(s.u16);
        w.writeInt32(s.i32);
        w.writeUint32(s.u32);
        w.writeInt64(s.i64);
        w.writeUint64(s.u64);
        w.writeFloat32(s.f32);
        w.writeFloat64(s.f64);
        w.writeBool(s.b);
        w.writeOctet(s.o);
        w.writeChar(s.ch);
        w.endAppendable(_tok);
    },
    encode(s: Prim, endian: EndianMode = "le", representation = 1): Uint8Array {
        const w = new Xcdr2Writer(endian, representation === 0 ? 8 : 4);
        this.encodeInto(w, s);
        return w.toBytes();
    },
    decodeFrom(r: Xcdr2Reader): Prim {
        const _tok = r.beginAppendable();
        const _f_i8: number = r.readInt8();
        const _f_u8: number = r.readUint8();
        const _f_i16: number = r.readInt16();
        const _f_u16: number = r.readUint16();
        const _f_i32: number = r.readInt32();
        const _f_u32: number = r.readUint32();
        const _f_i64: bigint = r.readInt64();
        const _f_u64: bigint = r.readUint64();
        const _f_f32: number = r.readFloat32();
        const _f_f64: number = r.readFloat64();
        const _f_b: boolean = r.readBool();
        const _f_o: number = r.readOctet();
        const _f_ch: Char = r.readChar();
        r.endAppendable(_tok);
        return {
            i8: _f_i8,
            u8: _f_u8,
            i16: _f_i16,
            u16: _f_u16,
            i32: _f_i32,
            u32: _f_u32,
            i64: _f_i64,
            u64: _f_u64,
            f32: _f_f32,
            f64: _f_f64,
            b: _f_b,
            o: _f_o,
            ch: _f_ch,
        };
    },
    decode(bytes: Uint8Array, offset = 0, length: number = bytes.length - offset, endian: EndianMode = "le", representation = 1): Prim {
        const r = new Xcdr2Reader(bytes, offset, length, endian, representation === 0 ? 8 : 4);
        return this.decodeFrom(r);
    },
    keyHash(s: Prim): Uint8Array {
        return new Uint8Array(16);
    },
};

